9	const THREE_ALIKE_BUNDLE_BASE = 60;
10	
11	const isThreeAlikeBundle = (items: any[]): boolean =>
12	  items.length === 3 && items.every((i) => i.type === items[0].type);
13	
14	const anyCursed = (items: any[]): boolean => items.some((i) => i.cursed);
15	
16	const anyHighlyEnchanted = (items: any[]): boolean =>
17	  items.some((i) => i.enchantment >= 5);
18	
19	const applyPercent = (amount: number, percent: number): number =>
20	  Math.ceil((amount * percent) / 100);
21	
22	const applyPercentIf = (condition: boolean, amount: number, percent: number): number =>
23	  condition ? applyPercent(amount, percent) : amount;
24	
25	const FIRST_INSURANCE_PERCENT = 110;
26	const CURSED_PERCENT = 150;
27	const ENCHANTMENT_PERCENT = 130;
28	const LOYALTY_DISCOUNT_PERCENT = 20;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const FIXED_FEE = 5;
31	
32	const applyDiscount = (amount: number, discountPercent: number): number =>
33	  Math.floor((amount * (100 - discountPercent)) / 100);
34	
35	const applyDiscountIf = (condition: boolean, amount: number, discountPercent: number): number =>
36	  condition ? applyDiscount(amount, discountPercent) : amount;
37	
38	const rawBaseFor = (items: any[]): number =>
39	  isThreeAlikeBundle(items)
40	    ? THREE_ALIKE_BUNDLE_BASE
41	    : basePriceByItemType[items[0].type];
42	
43	const isLoyalCustomer = (yearsWithMHPCO: number): boolean =>
44	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
45	
46	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
47	
48	const applyContractAdjustment = (amount: number, isRepeatContract: boolean): number =>
49	  isRepeatContract
50	    ? applyDiscount(amount, REPEAT_CONTRACT_DISCOUNT_PERCENT)
51	    : applyPercent(amount, FIRST_INSURANCE_PERCENT);
52	
53	const quotePremium = (items: any[], yearsWithMHPCO: number, isRepeatContract: boolean): number => {
54	  const base = rawBaseFor(items);
55	  const afterCursed = applyPercentIf(anyCursed(items), base, CURSED_PERCENT);
56	  const afterEnchantment = applyPercentIf(
57	    anyHighlyEnchanted(items),
58	    afterCursed,
59	    ENCHANTMENT_PERCENT,
60	  );
61	  const afterLoyalty = applyDiscountIf(
62	    isLoyalCustomer(yearsWithMHPCO),
63	    afterEnchantment,
64	    LOYALTY_DISCOUNT_PERCENT,
65	  );
66	  const afterContract = applyContractAdjustment(afterLoyalty, isRepeatContract);
67	  return afterContract + FIXED_FEE;
68	};
