70	export const runScenario = (scenario: any): unknown => {
71	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
72	  const results = scenario.steps.map((step: any, index: number) => ({
73	    premium: quotePremium(step.items, yearsWithMHPCO, index > 0),
74	  }));
75	  return { results };
76	};
